import React, { useEffect, useState } from "react";
import { useParams } from "react-router";
import { Cards } from "../components/data/Cards";

function DetailProduct() {
    let { id } = useParams();
    const [product, setProduct] = useState(false);
    useEffect(() => {
        setProduct(Cards.filter((el) => String(el.id) === String(id))[0])
    }, [id]);
    if (product) {
        return (
            <div className="Detail">
                <div className="Detail__card">
                    <div className="skidd"><h2>{product.skid}</h2></div>
                    <img src={product.img} alt="" />
                    <h1 className='data'>{product.title}</h1>
                    <div className="main">
                    <h3>{product.cost}</h3>
                   <p>{product.main}</p> 
                    </div>
                  <hr className="hr"/>
                    <div className="cod"><h2>Код товара: </h2>{product.cod}</div>
                </div>
            </div>
        );
    } else {
        return "Не найдено";
    }
}

export default DetailProduct;
